        /// This `private` method is a helper that provides an `NSImage`.
        /// - Parameter named: The name of the SFSymbol.
        /// - Returns: The named SFSymbol as an `NSImage`.
        private static func getSystemImage(named: String) -> NSImage {
            guard let image = NSImage(systemSymbolName: named, accessibilityDescription:  "This is the symbole for\(named)")
            else { return NSImage() }
            return image
        }
